mapper.select:
SELECT transport_dtl_id, transport_id, untpc, qty, amount, shipment_operation_date, calculation_cd, sender_receiver_cd, waybill_no, kind_cd, rmk, reg_id, reg_dt, chg_id, chg_dt, del_yn FROM transport_dtl WHERE del_yn = 'N'
AND sender_receiver_cd = #{senderReceiverCd}
AND transport_dtl_id = #{transportDtlId}
AND transport_id = #{transportId}
AND waybill_no = #{waybillNo}
AND CAST(shipment_operation_date AS DATE) >= CAST(#{startDate} AS DATE)
AND CAST(shipment_operation_date AS DATE) < CAST(#{endDate} AS DATE) + INTERVAL '1 day'
order by transport_dtl_id desc
